concept.syntax:
// Infinite loop — break to exit
loop {
    break;          // exit
}

// loop with return value
let result = loop { break 42; };

// while
while n > 0 {
    n -= 1;
}

// for with exclusive range (0,1,2,3,4)
for i in 0..5 { println!("{}", i); }

// for with inclusive range (0,1,2,3,4,5)
for i in 0..=5 { println!("{}", i); }

demo.code:
fn main() {
    for i in 1..=3 {
        println!("i = {}", i);
    }

    let answer = loop {
        break 99;
    };
    println!("answer = {}", answer);
}

